58	const (
59		CheckpointFilePerms = 0o644                    // File permissions for checkpoint files
60		CheckpointDirPerms  = 0o755                    // Directory permissions for checkpoint directories
61		GCTriggerInterval   = DefaultGCTriggerInterval // Interval for triggering GC during checkpoint loading
62	)
63	
64	// CheckpointMetrics represents metric data in a checkpoint file.
65	// Whenever the structure changes, update MarshalJSON as well!
66	type CheckpointMetrics struct {
67		Data      []schema.Float `json:"data"`
68		Frequency int64          `json:"frequency"`
69		Start     int64          `json:"start"`
70	}
71	
72	// CheckpointFile represents the hierarchical structure of a checkpoint file.
73	// It mirrors the Level tree structure from the MemoryStore.
74	type CheckpointFile struct {
75		Metrics  map[string]*CheckpointMetrics `json:"metrics"`
76		Children map[string]*CheckpointFile    `json:"children"`
77		From     int64                         `json:"from"`
78		To       int64                         `json:"to"`
79	}
80	
81	// lastCheckpoint tracks the timestamp of the last checkpoint creation.
82	var (
83		lastCheckpoint   time.Time
84		lastCheckpointMu sync.Mutex
85	)
86	
87	// Checkpointing starts a background worker that periodically saves metric data to disk.
88	//
89	// The checkpoint interval is read from Keys.CheckpointInterval (default: 12 hours).
90	//
91	// Format behaviour:
92	//   - "json": Writes a JSON snapshot file per host every interval
93	//   - "wal":  Writes a binary snapshot file per host every interval, then rotates
94	//     the current.wal files for all successfully checkpointed hosts
95	func Checkpointing(wg *sync.WaitGroup, ctx context.Context) {
96		lastCheckpointMu.Lock()
97		lastCheckpoint = time.Now()
98		lastCheckpointMu.Unlock()
99	
100		ms := GetMemoryStore()
101	
102		wg.Go(func() {
103			d := 12 * time.Hour // default checkpoint interval
104			if Keys.CheckpointInterval != "" {
105				parsed, err := time.ParseDuration(Keys.CheckpointInterval)
106				if err != nil {
107					cclog.Errorf("[METRICSTORE]> invalid checkpoint-interval %q: %s, using default 12h", Keys.CheckpointInterval, err)
108				} else {
109					d = parsed
110				}
111			}
112	
113			ticker := time.NewTicker(d)
114			defer ticker.Stop()
115	
116			for {
117				select {
118				case <-ctx.Done():
119					return
120				case <-ticker.C:
121					lastCheckpointMu.Lock()
122					from := lastCheckpoint
123					lastCheckpointMu.Unlock()
124	
125					now := time.Now()
126					cclog.Infof("[METRICSTORE]> start checkpointing (starting at %s)...", from.Format(time.RFC3339))
127	
128					if Keys.Checkpoints.FileFormat == "wal" {
129						// Pause WAL writes: the binary snapshot captures all in-memory
130						// data, so WAL records written during checkpoint are redundant
131						// and would be deleted during rotation anyway.
132						walCheckpointActive.Store(true)
133						n, hostDirs, err := ms.ToCheckpointWAL(Keys.Checkpoints.RootDir, from.Unix(), now.Unix())
134						if err != nil {
135							cclog.Errorf("[METRICSTORE]> binary checkpointing failed: %s", err.Error())
136						}
137						if n > 0 {
138							cclog.Infof("[METRICSTORE]> done: %d binary snapshot files created", n)
139							lastCheckpointMu.Lock()
140							lastCheckpoint = now
141							lastCheckpointMu.Unlock()
142							// Rotate WAL files for successfully checkpointed hosts.
143							RotateWALFiles(hostDirs)
144						}
145						walCheckpointActive.Store(false)
146						walDropped.Store(0)
147					} else {
148						n, err := ms.ToCheckpoint(Keys.Checkpoints.RootDir, from.Unix(), now.Unix())
149						if err != nil {
150							cclog.Errorf("[METRICSTORE]> checkpointing failed: %s", err.Error())
151						} else {
152							cclog.Infof("[METRICSTORE]> done: %d checkpoint files created", n)
153							lastCheckpointMu.Lock()
154							lastCheckpoint = now
155							lastCheckpointMu.Unlock()
156						}
157					}
158				}
159			}
160		})
161	}
