524	// fromCheckpoint loads all checkpoint files (JSON, binary snapshot, WAL) for a
525	// single host directory. Snapshot files are loaded first (sorted by timestamp),
526	// then current.wal is replayed on top.
527	func (l *Level) fromCheckpoint(m *MemoryStore, dir string, from int64) (int, error) {
528		direntries, err := os.ReadDir(dir)
529		if err != nil {
530			if os.IsNotExist(err) {
531				return 0, nil
532			}
533			return 0, err
534		}
535	
536		allFiles := make([]fs.DirEntry, 0)
537		var walEntry fs.DirEntry
538		filesLoaded := 0
539	
540		for _, e := range direntries {
541			if e.IsDir() {
542				// Legacy: skip subdirectories (only used by old Avro format).
543				// These are ignored; their data is not loaded.
544				cclog.Debugf("[METRICSTORE]> skipping subdirectory %s in checkpoint dir %s", e.Name(), dir)
545				continue
546			}
547	
548			name := e.Name()
549			if strings.HasSuffix(name, ".json") || strings.HasSuffix(name, ".bin") {
550				allFiles = append(allFiles, e)
551			} else if name == "current.wal" {
552				walEntry = e
553			}
554			// Silently ignore other files (e.g., .tmp, .bin.tmp from interrupted writes).
555		}
556	
557		files, err := findFiles(allFiles, from, true)
558		if err != nil {
559			return filesLoaded, err
560		}
561	
562		loaders := map[string]func(*MemoryStore, *os.File, int64) error{
563			".json": l.loadJSONFile,
564			".bin":  l.loadBinaryFile,
565		}
566	
567		for _, filename := range files {
568			ext := filepath.Ext(filename)
569			loader := loaders[ext]
570			if loader == nil {
571				cclog.Warnf("[METRICSTORE]> unknown extension for checkpoint file %s", filename)
572				continue
573			}
574	
575			err := func() error {
576				f, err := os.Open(path.Join(dir, filename))
577				if err != nil {
578					return err
579				}
580				defer f.Close()
581				return loader(m, f, from)
582			}()
583			if err != nil {
584				return filesLoaded, err
585			}
586			filesLoaded++
587		}
588	
589		// Replay WAL after all snapshot files so it fills in data since the last snapshot.
590		if walEntry != nil {
591			err := func() error {
592				f, err := os.Open(path.Join(dir, walEntry.Name()))
593				if err != nil {
594					return err
595				}
596				defer f.Close()
597				return l.loadWALFile(m, f, from)
598			}()
599			if err != nil {
600				// WAL errors are non-fatal: the snapshot already loaded the bulk of data.
601				cclog.Warnf("[METRICSTORE]> WAL replay error for %s: %v (data since last snapshot may be missing)", dir, err)
602			} else {
603				filesLoaded++
604			}
605		}
606	
607		return filesLoaded, nil
608	}
