610	// parseTimestampFromFilename extracts a Unix timestamp from a checkpoint filename.
611	// Supports ".json" (format: "<ts>.json") and ".bin" (format: "<ts>.bin").
612	func parseTimestampFromFilename(name string) (int64, error) {
613		switch {
614		case strings.HasSuffix(name, ".json"):
615			return strconv.ParseInt(name[:len(name)-5], 10, 64)
616		case strings.HasSuffix(name, ".bin"):
617			return strconv.ParseInt(name[:len(name)-4], 10, 64)
618		default:
619			return 0, fmt.Errorf("unknown checkpoint extension for file %q", name)
620		}
621	}
622	
623	// findFiles returns filenames from direntries whose timestamps satisfy the filter.
624	// If findMoreRecentFiles is true, returns files with timestamps >= t (plus the
625	// last file before t if t falls between two files).
626	func findFiles(direntries []fs.DirEntry, t int64, findMoreRecentFiles bool) ([]string, error) {
627		nums := map[string]int64{}
628		for _, e := range direntries {
629			name := e.Name()
630			if !strings.HasSuffix(name, ".json") && !strings.HasSuffix(name, ".bin") {
631				continue
632			}
633	
634			ts, err := parseTimestampFromFilename(name)
635			if err != nil {
636				return nil, err
637			}
638			nums[name] = ts
639		}
640	
641		sort.Slice(direntries, func(i, j int) bool {
642			a, b := direntries[i], direntries[j]
643			return nums[a.Name()] < nums[b.Name()]
644		})
645	
646		if len(nums) == 0 {
647			return nil, nil
648		}
649	
650		filenames := make([]string, 0)
651	
652		for i, e := range direntries {
653			ts1 := nums[e.Name()]
654	
655			if findMoreRecentFiles && t <= ts1 {
656				filenames = append(filenames, e.Name())
657			} else if !findMoreRecentFiles && ts1 <= t && ts1 != 0 {
658				filenames = append(filenames, e.Name())
659			}
660	
661			if i == len(direntries)-1 {
662				continue
663			}
664	
665			enext := direntries[i+1]
666			ts2 := nums[enext.Name()]
667	
668			if findMoreRecentFiles {
669				if ts1 < t && t < ts2 {
670					filenames = append(filenames, e.Name())
671				}
672			}
673		}
674	
675		return filenames, nil
676	}
